import{c as t,Q as a,j as r,m as o}from"./chunks/framework.-92krCd-.js";const u=JSON.parse('{"title":"IAM service","description":"","frontmatter":{},"headers":[],"relativePath":"reference/components/iam-service.md","filePath":"reference/components/iam-service.md"}'),n={name:"reference/components/iam-service.md"};function s(i,e,l,d,c,p){return a(),r("div",null,[...e[0]||(e[0]=[o(`<h1 id="iam-service" tabindex="-1">IAM service <a class="header-anchor" href="#iam-service" aria-label="Permalink to &quot;IAM service&quot;">​</a></h1><h2 id="purpose" tabindex="-1">Purpose <a class="header-anchor" href="#purpose" aria-label="Permalink to &quot;Purpose&quot;">​</a></h2><p>The <strong>IAM service</strong> is a GraphQL-based identity and access management service for Platform Mesh. It is composed of two integrated layers:</p><ul><li><strong>Keycloak</strong> — the OIDC identity provider used for authentication. Users log in via Keycloak and receive JWT tokens consumed by all Platform Mesh services. The IAM service uses the Keycloak Admin API for user queries and enrichment.</li><li><strong>OpenFGA</strong> — a relationship-based authorization engine (inspired by Google Zanzibar). Fine-grained permissions (for example workspace membership, role assignments) are stored as tuples and evaluated by OpenFGA at request time.</li></ul><p>The service consumes per-organization OpenFGA stores provisioned by the <a href="./security-operator.html">Security operator</a>, writes role-assignment tuples for IAM workflows, and exposes IAM operations consumed by the Portal and other Platform Mesh components. It is the runtime peer of the <a href="./account-operator.html">Account operator</a> for identity and access-management workflows.</p><h2 id="runtime-role" tabindex="-1">Runtime role <a class="header-anchor" href="#runtime-role" aria-label="Permalink to &quot;Runtime role&quot;">​</a></h2><p>The IAM service does not own <code>Store</code> lifecycle. It looks up the organization&#39;s OpenFGA store by name, writes role-assignment tuples, and evaluates tuples through OpenFGA. The <code>Store</code> CRD and authorization model are reconciled by the <a href="./security-operator.html">Security operator</a>.</p><p>All routing goes through a GraphQL API. Requests pass through a kcp middleware layer that injects user context from the JWT token, then reach resolvers protected by an <code>@Authorized</code> directive that evaluates OpenFGA tuples before returning data.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>GraphQL Request</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>kcp middleware (injects user context from JWT)</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>GraphQL Resolver (@Authorized directive)</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>OpenFGA tuple evaluation + Keycloak user enrichment</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>Response</span></span></code></pre></div><p><strong>Role model</strong> — two roles are defined per resource scope:</p><table tabindex="0"><thead><tr><th>Role</th><th>Description</th></tr></thead><tbody><tr><td><code>Owner</code></td><td>Full access to all resources within the account</td></tr><tr><td><code>Member</code></td><td>Limited access; can view and interact but cannot administrate</td></tr></tbody></table><p><strong>No traditional database</strong> — authorization state is stored exclusively as OpenFGA tuples, enabling distributed authorization decisions and consistency through kcp coordination.</p><h2 id="technology-stack" tabindex="-1">Technology stack <a class="header-anchor" href="#technology-stack" aria-label="Permalink to &quot;Technology stack&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Component</th><th>Technology</th></tr></thead><tbody><tr><td>Language</td><td>Go 1.26+</td></tr><tr><td>API</td><td>GraphQL (schema-first via gqlgen)</td></tr><tr><td>Authorization</td><td>OpenFGA (gRPC)</td></tr><tr><td>Identity provider</td><td>Keycloak (OIDC / OAuth2)</td></tr><tr><td>Multi-cluster</td><td>kcp (kcp-dev controller-runtime fork)</td></tr><tr><td>Observability</td><td>OpenTelemetry + zerolog</td></tr><tr><td>Container</td><td>Distroless static binary, non-root (UID 1001)</td></tr></tbody></table><h2 id="configuration" tabindex="-1">Configuration <a class="header-anchor" href="#configuration" aria-label="Permalink to &quot;Configuration&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Variable</th><th>Purpose</th></tr></thead><tbody><tr><td><code>KUBECONFIG</code></td><td>Path to the Kubernetes / kcp cluster config</td></tr><tr><td><code>KEYCLOAK_CLIENT_SECRET</code></td><td>Keycloak OAuth2 client secret (environment only — never pass via CLI args)</td></tr></tbody></table><p>Copy <code>.env.sample</code> to <code>.env</code> and populate the values before running locally.</p><h2 id="repository" tabindex="-1">Repository <a class="header-anchor" href="#repository" aria-label="Permalink to &quot;Repository&quot;">​</a></h2><ul><li><a href="https://github.com/platform-mesh/iam-service" target="_blank" rel="noreferrer">github.com/platform-mesh/iam-service</a></li></ul><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./iam-ui.html">IAM UI</a></li><li><a href="./openfga.html">OpenFGA</a></li><li><a href="./rebac-authz-webhook.html">rebac-authz-webhook</a></li><li><a href="/pr-preview/pr-219/concepts/identity-and-authorization.html">Identity and authorization</a></li></ul>`,21)])])}const m=t(n,[["render",s]]);export{u as __pageData,m as default};
